/bin/zsh -lc "cd /Users/daniel/workspace/repos/orbit && find crates -name Cargo.toml | sort | while read -r f; do awk '
  /"'^'"\\[["'^]]+'"\\]/ { sec="'$0 }
  (sec=="[dependencies]" || sec=="[dev-dependencies]" || sec=="[build-dependencies]") && $0 ~ /''^[[:space:]]*orbit-knowledge[[:space:]]*=/ {
    print FILENAME ":" NR ":" sec ":" $0
  }
'"' \""'$f"; done'

